// === Fusion du résultat Ollama (protocole JSON structuré) avec la sortie règles ===
// Cette couche est OPTIONNELLE : si Ollama est indisponible, en erreur, ou renvoie
// un JSON invalide/incomplet, texte_anonymise_final reste null et mapping_reverse
// reste strictement celui de la couche règles. Le pipeline aval n'échoue jamais ici.

const anonOut = $('Code JS (anonymisation)').first().json;
const ollamaResponse = $input.first().json;

const baseMapping = anonOut.mapping_reverse || {};

let texteFinal = null;
let ollamaMappingPropre = null;
let ollamaError = null;
let ollamaUsed = false;
let nbEntitesDetectees = 0;

try {
  const raw = ollamaResponse && ollamaResponse.response ? String(ollamaResponse.response).trim() : '';
  if (!raw) {
    throw new Error('Réponse Ollama vide.');
  }

  // Sécurité : Ollama respecte rarement les balises de code avec format:"json",
  // mais on nettoie au cas où un modèle les ajoute quand même.
  let cleaned = raw.replace(/^```[a-zA-Z]*\n?/, '');
  if (cleaned.endsWith('```')) {
    cleaned = cleaned.slice(0, -3);
  }
  cleaned = cleaned.trim();

  const parsed = JSON.parse(cleaned);

  if (
    !parsed ||
    typeof parsed.anonymized_text !== 'string' ||
    parsed.anonymized_text.length === 0 ||
    typeof parsed.mapping !== 'object' ||
    parsed.mapping === null ||
    Array.isArray(parsed.mapping)
  ) {
    throw new Error('JSON Ollama ne respecte pas le schéma attendu (anonymized_text / mapping).');
  }

  // Garde-fou n°7 : on ignore toute tentative de renommer/écraser un placeholder
  // déjà créé par la couche règles (Client A, [VILLE], [EMAIL_n], [PHONE_n], [URL_n], [REF_n]).
  const cleanMapping = {};
  for (const [placeholder, valeurOriginale] of Object.entries(parsed.mapping)) {
    if (Object.prototype.hasOwnProperty.call(baseMapping, placeholder)) {
      continue; // placeholder déjà utilisé par les règles -> jamais écrasé
    }
    cleanMapping[placeholder] = valeurOriginale;
  }

  texteFinal = parsed.anonymized_text;
  ollamaMappingPropre = cleanMapping;
  nbEntitesDetectees = Object.keys(cleanMapping).length;
  ollamaUsed = true;
} catch (e) {
  ollamaError = 'Erreur lors du traitement de la réponse Ollama: ' + e.message;
}

// Garde-fou : si l'appel HTTP a échoué (onError: continueRegularOutput), l'item
// peut contenir un champ "error" au lieu de "response".
if (!ollamaUsed && ollamaResponse && ollamaResponse.error) {
  ollamaError = 'Ollama HTTP error: ' + JSON.stringify(ollamaResponse.error);
}

// mapping_reverse final : fusion règles + Ollama si succès, sinon règles seules (inchangé).
const mappingReverseFinal = ollamaUsed
  ? { ...baseMapping, ...ollamaMappingPropre }
  : baseMapping;

return [
  {
    json: {
      // --- Champs de la couche règles, préservés ---
      texte_anonymise: anonOut.texte_anonymise,
      mapping_reverse: mappingReverseFinal,
      detection: anonOut.detection,
      nb_remplacements: anonOut.nb_remplacements,
      longueur_originale: anonOut.longueur_originale,
      longueur_anonymisee: anonOut.longueur_anonymisee,
      anonymisation_stats: anonOut.anonymisation_stats,
      // --- Nouvelle couche IA locale (Ollama), optionnelle et réversible ---
      texte_anonymise_final: ollamaUsed ? texteFinal : null,
      anonymisation_ia: {
        utilisee: ollamaUsed,
        moteur: 'Ollama',
        nb_entites_detectees: nbEntitesDetectees,
        erreur: ollamaError,
      },
    },
  },
];

const response = $input.first().json;
let xml = response?.choices?.[0]?.message?.content ?? '';
xml = String(xml).trim();
xml = xml.replace(/^```xml\s*/i, '');
xml = xml.replace(/^```\s*/i, '');
xml = xml.replace(/\s*```$/i, '');
xml = xml.trim();

const markdownSource = $('Read Markdown as Text').first().json;
const markdown = markdownSource.markdown || markdownSource.text || '';

return [{
  json: {
    xml,
    markdown,
  },
}];

const item = $input.first();
const now = Date.now();

return [{
  json: {
    ...item.json,
    marker_poll_count: 0,
    marker_started_at: now,
    marker_max_polls: 10,
    marker_max_elapsed_ms: 300000,
  },
  binary: item.binary,
}];

const item = $input.first();
const now = Date.now();
const pollCount = Number(item.json.marker_poll_count ?? 0) + 1;
const startedAt = Number(item.json.marker_started_at ?? now);
const maxPolls = Number(item.json.marker_max_polls ?? 10);
const maxElapsedMs = Number(item.json.marker_max_elapsed_ms ?? 300000);
const elapsedMs = now - startedAt;
const timedOut = pollCount >= maxPolls || elapsedMs >= maxElapsedMs;

return [{
  json: {
    ...item.json,
    marker_timed_out: timedOut,
    marker_poll_count: pollCount,
    marker_started_at: startedAt,
    marker_max_polls: maxPolls,
    marker_max_elapsed_ms: maxElapsedMs,
    marker_elapsed_ms: elapsedMs,
    marker_last_poll_at: now,
  },
  binary: item.binary,
}];
